/* ============================================================================
 seed_prompt_library.sql  --  NALLO_APP.rtds
 
 Seeds CLEAN prompt data for ONE prompt library (by PromptLibraryID) into:
 rtds.PromptLibrary   (parent, find-or-create)
 rtds.Prompt          (all prompts in the library)
 rtds.PromptVersion   (all language versions of those prompts)
 
 Source data is embedded from the rtds_data_extract CSVs:
 rtds_promptLibrary.csv  (incl. CompanyProjectID), rtds_prompt.csv,
 rtds_promptVersion.csv.
 
 DESIGN CHOICES
 - Parameterized   : set @PromptLibraryID; the whole extract is staged in
 #temp tables and the chosen library is filtered out.
 - Preserve IDs    : SET IDENTITY_INSERT keeps the original
 PromptLibraryID / PromptID / PromptVersionID.
 - Idempotent      : every insert is guarded by NOT EXISTS on the PK, so
 re-running (or running for a second library) never
 duplicates rows and never fails on existing keys.
 
 All writes run in a single transaction (XACT_ABORT ON -> auto-rollback).
 Target: Microsoft SQL Server (T-SQL).
 ============================================================================ */
SET XACT_ABORT ON;
SET NOCOUNT ON;
GO
IF NOT EXISTS (
        SELECT 1
        FROM sys.schemas
        WHERE name = 'rtds'
    ) THROW 60070,
    'Schema "rtds" not found. Aborting seed.',
    1;
GO
    /* ============================================================================
     INPUT  (edit here)
     ============================================================================ */
DECLARE @PromptLibraryID int = 3;
-- <<< library to seed
DECLARE @SeedDictionaries bit = 0;
-- 1 = also seed referenced
--     Dic_PromptLanguage / Application
/* ----------------------------------------------------------------------------
 STAGING  (full extract, loaded into #temp tables; filtered below)
 ---------------------------------------------------------------------------- */
IF OBJECT_ID('tempdb..#SrcLibrary') IS NOT NULL DROP TABLE #SrcLibrary;
IF OBJECT_ID('tempdb..#SrcPrompt') IS NOT NULL DROP TABLE #SrcPrompt;
IF OBJECT_ID('tempdb..#SrcPromptVersion') IS NOT NULL DROP TABLE #SrcPromptVersion;
CREATE TABLE #SrcLibrary (
PromptLibraryID int NOT NULL PRIMARY KEY,
CompanyProjectID int NOT NULL,
BasePath varchar(255) NOT NULL,
DateCreated datetime2 NULL,
CreatedBy varchar(50) NULL,
DateUpdated datetime2 NULL,
UpdatedBy varchar(50) NULL
);
CREATE TABLE #SrcPrompt (
PromptID int NOT NULL PRIMARY KEY,
PromptLibraryID int NOT NULL,
DicPromptApplicationID int NULL,
Name varchar(255) NOT NULL,
Description varchar(255) NULL,
IsDisplayed bit NOT NULL,
DateCreated datetime2 NULL,
CreatedBy varchar(50) NULL,
DateUpdated datetime2 NULL,
UpdatedBy varchar(50) NULL
);
CREATE TABLE #SrcPromptVersion (
PromptVersionID int NOT NULL PRIMARY KEY,
PromptID int NOT NULL,
DicPromptLanguageID int NOT NULL,
Path varchar(255) NOT NULL,
Text varchar(max) NULL,
DateCreated datetime2 NULL,
CreatedBy varchar(50) NULL,
DateUpdated datetime2 NULL,
UpdatedBy varchar(50) NULL
);
GO
