    /* ============================================================================
     RE-DECLARE INPUT  (variables do not survive a GO batch boundary; #temp does)
     ============================================================================ */
DECLARE @PromptLibraryID int = 3;
-- <<< keep in sync with the value above
DECLARE @SeedDictionaries bit = 0;
-- <<< keep in sync
DECLARE @CreatedBy varchar(50) = 'rtds-seed';
DECLARE @now datetime2 = SYSUTCDATETIME();
/* -- existence check (read-only) ------------------------------------------- */
IF NOT EXISTS (
    SELECT 1
    FROM #SrcLibrary WHERE PromptLibraryID = @PromptLibraryID)
        THROW 54101,
        'UNKNOWN_LIBRARY: @PromptLibraryID not present in the extract.',
        1;
DECLARE @LibraryExists bit = CASE
        WHEN EXISTS (
            SELECT 1
            FROM rtds.PromptLibrary
            WHERE PromptLibraryID = @PromptLibraryID
        ) THEN 1
        ELSE 0
    END;
/* -- referenced dictionary keys must exist (unless we are seeding them) ----- */
IF @SeedDictionaries = 0 BEGIN IF EXISTS (
    SELECT 1
    FROM #SrcPrompt p
    WHERE p.PromptLibraryID = @PromptLibraryID
        AND p.DicPromptApplicationID IS NOT NULL
        AND NOT EXISTS (
            SELECT 1
            FROM rtds.Dic_PromptApplication d
            WHERE d.DicPromptApplicationID = p.DicPromptApplicationID
        )
) THROW 54103,
'UNKNOWN_APPLICATION: a prompt references a DicPromptApplicationID not in rtds.Dic_PromptApplication (set @SeedDictionaries = 1 or seed it first).',
1;
IF EXISTS (
    SELECT 1
    FROM #SrcPromptVersion pv
        JOIN #SrcPrompt p ON p.PromptID = pv.PromptID
    WHERE p.PromptLibraryID = @PromptLibraryID
        AND NOT EXISTS (
            SELECT 1
            FROM rtds.Dic_PromptLanguage d
            WHERE d.DicPromptLanguageID = pv.DicPromptLanguageID
        )
) THROW 54104,
'UNKNOWN_LANGUAGE: a prompt version references a DicPromptLanguageID not in rtds.Dic_PromptLanguage (set @SeedDictionaries = 1 or seed it first).',
1;
END
/* ============================================================================
 WRITE  (single transaction)
 ============================================================================ */
DECLARE @libIns int = 0,
    @appIns int = 0,
    @langIns int = 0,
    @promptIns int = 0,
    @verIns int = 0;
BEGIN TRY BEGIN TRANSACTION;
/* -- 0. optionally seed referenced dictionary rows (idempotent) --------- */
IF @SeedDictionaries = 1 BEGIN
SET IDENTITY_INSERT rtds.Dic_PromptApplication ON;
INSERT INTO rtds.Dic_PromptApplication (
        DicPromptApplicationID,
        Name,
        FilePrefix,
        DateCreated,
        CreatedBy
    )
SELECT DISTINCT p.DicPromptApplicationID,
    'App_' + CAST(p.DicPromptApplicationID AS varchar(10)),
    'App' + CAST(p.DicPromptApplicationID AS varchar(10)),
    @now,
    @CreatedBy
FROM #SrcPrompt p
WHERE p.PromptLibraryID = @PromptLibraryID
    AND p.DicPromptApplicationID IS NOT NULL
    AND NOT EXISTS (
        SELECT 1
        FROM rtds.Dic_PromptApplication d
        WHERE d.DicPromptApplicationID = p.DicPromptApplicationID
    );
SET @appIns = @@ROWCOUNT;
SET IDENTITY_INSERT rtds.Dic_PromptApplication OFF;
SET IDENTITY_INSERT rtds.Dic_PromptLanguage ON;
INSERT INTO rtds.Dic_PromptLanguage (
        DicPromptLanguageID,
        [Key],
        Language,
        DateCreated,
        CreatedBy
    )
SELECT DISTINCT pv.DicPromptLanguageID,
    'L' + CAST(pv.DicPromptLanguageID AS varchar(10)),
    'Lang_' + CAST(pv.DicPromptLanguageID AS varchar(10)),
    @now,
    @CreatedBy
FROM #SrcPromptVersion pv
    JOIN #SrcPrompt p ON p.PromptID = pv.PromptID
WHERE p.PromptLibraryID = @PromptLibraryID
    AND NOT EXISTS (
        SELECT 1
        FROM rtds.Dic_PromptLanguage d
        WHERE d.DicPromptLanguageID = pv.DicPromptLanguageID
    );
SET @langIns = @@ROWCOUNT;
SET IDENTITY_INSERT rtds.Dic_PromptLanguage OFF;
END
/* -- 1. PromptLibrary parent (preserve id, only if missing) ------------- */
IF @LibraryExists = 0 BEGIN
SET IDENTITY_INSERT rtds.PromptLibrary ON;
INSERT INTO rtds.PromptLibrary (
        PromptLibraryID,
        CompanyProjectID,
        BasePath,
        DateCreated,
        CreatedBy,
        DateUpdated,
        UpdatedBy
    )
SELECT s.PromptLibraryID,
    s.CompanyProjectID,
    s.BasePath,
    ISNULL(s.DateCreated, @now),
    ISNULL(s.CreatedBy, @CreatedBy),
    s.DateUpdated,
    s.UpdatedBy
FROM #SrcLibrary s
WHERE s.PromptLibraryID = @PromptLibraryID;
SET @libIns = @@ROWCOUNT;
SET IDENTITY_INSERT rtds.PromptLibrary OFF;
END
/* -- 2. Prompt rows (preserve id, skip ones already present) ------------ */
SET IDENTITY_INSERT rtds.Prompt ON;
INSERT INTO rtds.Prompt (
        PromptID,
        PromptLibraryID,
        DicPromptApplicationID,
        Name,
        Description,
        IsDisplayed,
        DateCreated,
        CreatedBy,
        DateUpdated,
        UpdatedBy
    )
SELECT s.PromptID,
    s.PromptLibraryID,
    s.DicPromptApplicationID,
    s.Name,
    s.Description,
    s.IsDisplayed,
    ISNULL(s.DateCreated, @now),
    ISNULL(s.CreatedBy, @CreatedBy),
    s.DateUpdated,
    s.UpdatedBy
FROM #SrcPrompt s
WHERE s.PromptLibraryID = @PromptLibraryID
    AND NOT EXISTS (
        SELECT 1
        FROM rtds.Prompt t
        WHERE t.PromptID = s.PromptID
    );
SET @promptIns = @@ROWCOUNT;
SET IDENTITY_INSERT rtds.Prompt OFF;
/* -- 3. PromptVersion rows (preserve id, skip ones already present) ------ */
SET IDENTITY_INSERT rtds.PromptVersion ON;
INSERT INTO rtds.PromptVersion (
        PromptVersionID,
        PromptID,
        DicPromptLanguageID,
        Path,
        Text,
        DateCreated,
        CreatedBy,
        DateUpdated,
        UpdatedBy
    )
SELECT s.PromptVersionID,
    s.PromptID,
    s.DicPromptLanguageID,
    s.Path,
    s.Text,
    ISNULL(s.DateCreated, @now),
    ISNULL(s.CreatedBy, @CreatedBy),
    s.DateUpdated,
    s.UpdatedBy
FROM #SrcPromptVersion s
    JOIN #SrcPrompt p ON p.PromptID = s.PromptID
WHERE p.PromptLibraryID = @PromptLibraryID
    AND NOT EXISTS (
        SELECT 1
        FROM rtds.PromptVersion t
        WHERE t.PromptVersionID = s.PromptVersionID
    );
SET @verIns = @@ROWCOUNT;
SET IDENTITY_INSERT rtds.PromptVersion OFF;
COMMIT TRANSACTION;
PRINT 'RTDS prompt seed complete for PromptLibraryID ' + CAST(@PromptLibraryID AS varchar(10)) + '.';
PRINT '  Dic_PromptApplication inserted : ' + CAST(@appIns AS varchar(10));
PRINT '  Dic_PromptLanguage inserted    : ' + CAST(@langIns AS varchar(10));
PRINT '  PromptLibrary inserted         : ' + CAST(@libIns AS varchar(10));
PRINT '  Prompt inserted                : ' + CAST(@promptIns AS varchar(10));
PRINT '  PromptVersion inserted         : ' + CAST(@verIns AS varchar(10));
SELECT @PromptLibraryID AS PromptLibraryID,
    @libIns AS PromptLibraryInserted,
    @promptIns AS PromptsInserted,
    @verIns AS PromptVersionsInserted,
    @appIns AS DicApplicationInserted,
    @langIns AS DicLanguageInserted;
END TRY BEGIN CATCH IF XACT_STATE() <> 0 ROLLBACK TRANSACTION;
/* IDENTITY_INSERT is a session setting (not rolled back); reset it.
 OFF on a table that is already OFF is a harmless no-op. */
SET IDENTITY_INSERT rtds.PromptVersion OFF;
SET IDENTITY_INSERT rtds.Prompt OFF;
SET IDENTITY_INSERT rtds.PromptLibrary OFF;
SET IDENTITY_INSERT rtds.Dic_PromptLanguage OFF;
SET IDENTITY_INSERT rtds.Dic_PromptApplication OFF;
THROW;
END CATCH
GO
    /* cleanup staging */
    IF OBJECT_ID('tempdb..#SrcLibrary') IS NOT NULL DROP TABLE #SrcLibrary;
    IF OBJECT_ID('tempdb..#SrcPrompt') IS NOT NULL DROP TABLE #SrcPrompt;
    IF OBJECT_ID('tempdb..#SrcPromptVersion') IS NOT NULL DROP TABLE #SrcPromptVersion;
GO
    /* ============================================================================
     VERIFY (optional, read-only; run after seeding -- set @PromptLibraryID)
     ============================================================================ */
    /*
     DECLARE @PromptLibraryID int = 1;
     SELECT p.PromptID, p.Name, p.IsDisplayed, dpa.Name AS Application,
     pv.PromptVersionID, dl.[Key] AS Lang, pv.Path, pv.Text
     FROM   rtds.Prompt p
     LEFT JOIN rtds.Dic_PromptApplication dpa ON dpa.DicPromptApplicationID = p.DicPromptApplicationID
     LEFT JOIN rtds.PromptVersion pv          ON pv.PromptID = p.PromptID
     LEFT JOIN rtds.Dic_PromptLanguage dl     ON dl.DicPromptLanguageID = pv.DicPromptLanguageID
     WHERE  p.PromptLibraryID = @PromptLibraryID
     ORDER BY p.PromptID, pv.PromptVersionID;
     */